local pR = require(script.Parent.Symbol)
local pM = require(script.Parent.strict)
local qK = require(script.Parent.Portal)
local qL = newproxy(true)
local qM = {
	Portal = pR.named("Portal"),
	Host = pR.named("Host"),
	Function = pR.named("Function"),
	Stateful = pR.named("Stateful"),
	Fragment = pR.named("Fragment"),
}
function qM.of(d3)
	if typeof(d3) ~= "table" then
		return nil
	end
	return d3[qL]
end
local qN = { ["string"] = qM.Host, ["function"] = qM.Function, ["table"] = qM.Stateful }
function qM.fromComponent(qO)
	if qO == qK then
		return qL.Portal
	else
		return qN[typeof(qO)]
	end
end
getmetatable(qL).__index = qM
pM(qM, "ElementKind")
return qL
